import{_ as l,o as i,c as e,ag as r}from"./chunks/framework.BuUvxvtQ.js";const u=JSON.parse('{"title":"Общие рекомендации по безопасности","description":"","frontmatter":{},"headers":[],"relativePath":"general-security.md","filePath":"general-security.md"}'),t={name:"general-security.md"};function d(o,a,h,s,c,n){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="общие-рекомендации-по-безопасности" tabindex="-1">Общие рекомендации по безопасности <a class="header-anchor" href="#общие-рекомендации-по-безопасности" aria-label="Permalink to &quot;Общие рекомендации по безопасности&quot;">​</a></h1><p>Эта страница собирает базовые правила, которые подходят для большинства социальных сетей и мессенджеров.</p><h2 id="_1-создаваите-надежные-пароли" tabindex="-1">1. Создавайте надежные пароли <a class="header-anchor" href="#_1-создаваите-надежные-пароли" aria-label="Permalink to &quot;1. Создавайте надежные пароли&quot;">​</a></h2><ul><li>используйте длинные пароли или парольные фразы не короче 12-16 символов;</li><li>комбинируйте слова, цифры и специальные знаки, если сервис это поддерживает;</li><li>не используйте очевидные данные: имя, дату рождения, номер телефона;</li><li>не повторяйте один пароль в нескольких сервисах;</li><li>храните пароли в надежном менеджере паролей, а не в заметках без защиты.</li></ul><h2 id="_2-включаите-двухфакторную-аутентификацию" tabindex="-1">2. Включайте двухфакторную аутентификацию <a class="header-anchor" href="#_2-включаите-двухфакторную-аутентификацию" aria-label="Permalink to &quot;2. Включайте двухфакторную аутентификацию&quot;">​</a></h2><p>2FA добавляет второй шаг проверки после ввода пароля. Даже если пароль стал известен постороннему, дополнительный код снижает риск входа.</p><div class="card-grid"><div class="info-card"><h3>Предпочтительные варианты</h3><p>Приложение-аутентификатор, встроенные подтверждения входа, резервные коды, если платформа их предоставляет.</p></div><div class="info-card"><h3>Что важно помнить</h3><p>Сохраните резервные коды в безопасном месте и заранее проверьте, как восстанавливается доступ при смене телефона.</p></div></div><h2 id="_3-проверяите-активные-сессии" tabindex="-1">3. Проверяйте активные сессии <a class="header-anchor" href="#_3-проверяите-активные-сессии" aria-label="Permalink to &quot;3. Проверяйте активные сессии&quot;">​</a></h2><ul><li>завершайте входы на старых телефонах и компьютерах;</li><li>обращайте внимание на неизвестные местоположения и устройства;</li><li>после подозрительной активности сразу меняйте пароль и завершайте все лишние сеансы.</li></ul><h2 id="_4-настраиваите-приватность" tabindex="-1">4. Настраивайте приватность <a class="header-anchor" href="#_4-настраиваите-приватность" aria-label="Permalink to &quot;4. Настраивайте приватность&quot;">​</a></h2><div class="platform-grid"><div class="platform-card"><h3>Профиль</h3><p>Ограничьте видимость номера телефона, даты рождения, списка друзей, геолокации и архивных публикаций.</p></div><div class="platform-card"><h3>Публикации</h3><p>Проверяйте, кто может видеть новые записи, истории, фотоальбомы и комментарии.</p></div><div class="platform-card"><h3>Контакты</h3><p>Сократите объем сведений, по которым вас можно легко найти и связать с другими сервисами.</p></div></div><h2 id="_5-учитесь-распознавать-фишинг" tabindex="-1">5. Учитесь распознавать фишинг <a class="header-anchor" href="#_5-учитесь-распознавать-фишинг" aria-label="Permalink to &quot;5. Учитесь распознавать фишинг&quot;">​</a></h2><ul><li>давление временем: «срочно подтвердите», «аккаунт будет заблокирован»;</li><li>незнакомый адрес сайта или странный домен;</li><li>просьба ввести пароль, коды подтверждения или резервные коды;</li><li>ошибки в тексте, странный тон, неожиданные вложения;</li><li>ссылка приходит там, где вы ее не ожидали.</li></ul><h2 id="_6-осторожно-относитесь-к-ссылкам-и-сообщениям" tabindex="-1">6. Осторожно относитесь к ссылкам и сообщениям <a class="header-anchor" href="#_6-осторожно-относитесь-к-ссылкам-и-сообщениям" aria-label="Permalink to &quot;6. Осторожно относитесь к ссылкам и сообщениям&quot;">​</a></h2><ol><li>Не переходите по ссылкам автоматически.</li><li>Сначала оцените контекст: почему вам это прислали и кто именно.</li><li>Проверяйте адрес сайта полностью.</li><li>Если сообщение вызывает сомнение, откройте сервис вручную через официальное приложение или сохраненную закладку.</li></ol><h2 id="_7-восстанавливаите-доступ-безопасно" tabindex="-1">7. Восстанавливайте доступ безопасно <a class="header-anchor" href="#_7-восстанавливаите-доступ-безопасно" aria-label="Permalink to &quot;7. Восстанавливайте доступ безопасно&quot;">​</a></h2><ul><li>используйте только официальные формы восстановления;</li><li>не передавайте коды из SMS и приложения-аутентификатора;</li><li>заранее обновите резервную почту и номер телефона;</li><li>после восстановления доступа проверьте активные устройства, почту, привязанные приложения и настройки безопасности.</li></ul><div class="screenshot-placeholder"> Здесь можно разместить актуальный скриншот универсальных настроек безопасности: пароль, 2FA, список активных сеансов, резервные коды. </div>',18)])])}const p=l(t,[["render",d]]);export{u as __pageData,p as default};
